void initializePopulation() {
    population.clear();
    for (int i = 0; i < POPULATION_SIZE; ++i) {
        std::string individual(TARGET.size(), ' ');
        std::generate(individual.begin(), individual.end(), [&]() { return 'A' + rand() % ('Z' - 'A' + 1); });
        population.push_back(individual);
    }
}
